export async function seedForecasts(db: NodePgDatabase<typeof schema>) {
  console.log('Seeding forecasts...')

  // Insert in batches to avoid overwhelming the database
  const batchSize = 100
  let inserted = 0

  for (let i = 0; i < SEED_FORECASTS.length; i += batchSize) {
    const batch = SEED_FORECASTS.slice(i, i + batchSize)
    await db.insert(forecasts).values(batch)
    inserted += batch.length
  }

  console.log(`Created ${inserted} forecast records`)
}
